import { useEffect, useState } from "react"
function Crypto() {
  let [cryptodata, changecryptodata] = useState([])
  let [sparkline, changesparkline] = useState([])
  useEffect(() => {
    async function fetchcoins() {
      let fetched = await fetch("https://api.coingecko.com/api/v3/coins/markets?vs_currency=usd&ids=bitcoin,ethereum,binancecoin,ripple,solana,tron,dogecoin,monero")
      let fetchedjson = await fetched.json()
      changecryptodata(fetchedjson)
    }
    fetchcoins()
    async function fetchgraph() {
      let arr = ["BTCUSDT", "ETHUSDT", "BNBUSDT", "XRPUSDT", "SOLUSDT", "TRXUSDT", "DOGEUSDT", "XMRUSDT"]
      let response = arr.map( async (item) =>
      {
        let res = await fetch(`https://api.binance.com/api/v3/klines?symbol=${item}&interval=1h&limit=10`)
        return await res.json()
      })
      let allresult = await Promise.all(response)
      changesparkline(allresult.flat())
    }
    fetchgraph()
  }, [])
  useEffect(() => {
    console.log(sparkline)
  }, [sparkline, cryptodata])
  return<>

  </>
}
export default Crypto
